const input = $input.first().json;
const mergedData = $('Gather Intelligence').first().json;
const weekNumber = $('System Config').first().json.weekNumber;
const todayDate = $('System Config').first().json.todayDate;

let analysis;
try {
  const content = input.choices[0].message.content;
  const cleaned = content
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  analysis = JSON.parse(jsonMatch ? jsonMatch[0] : cleaned);
} catch(e) {
  analysis = {
    trends: [{ topic: 'AI automation continues to grow', relevance: 7, source: 'general' }],
    competitor_moves: [],
    opportunities: [{ topic: 'Share automation tips for SMBs', angle: 'Practical how-to content', priority: 'medium', platforms: ['TikTok', 'Instagram'] }],
    summary: 'Unable to fully parse AI analysis. Using fallback content opportunities.'
  };
}

// Build insight records for Airtable
const insights = [];

// Add trend insights
for (const trend of (analysis.trends || [])) {
  insights.push({
    title: trend.topic,
    sourceType: 'trend',
    source: trend.source || 'AI Analysis',
    summary: analysis.summary || '',
    keyThemes: JSON.stringify(analysis.trends.map(t => t.topic)),
    contentOpportunities: JSON.stringify(analysis.opportunities || []),
    relevanceScore: trend.relevance || 5,
    week: weekNumber,
    createdAt: todayDate
  });
}

// Add competitor move insights
for (const move of (analysis.competitor_moves || [])) {
  insights.push({
    title: `${move.competitor}: ${move.move}`,
    sourceType: 'competitor',
    source: move.competitor,
    summary: move.our_angle || '',
    keyThemes: JSON.stringify([move.move]),
    contentOpportunities: JSON.stringify([{ topic: move.our_angle, angle: 'Competitive response' }]),
    relevanceScore: 7,
    week: weekNumber,
    createdAt: todayDate
  });
}

return {
  json: {
    analysis: analysis,
    insights: insights,
    hashUpdates: mergedData.hashUpdates || [],
    tokensUsed: input.usage ? input.usage.total_tokens : 0,
    totalSources: mergedData.totalSources
  }
};

const { insights } = $input.first().json;

// Return each insight as a separate item for batch Airtable create
return insights.map(insight => ({
  json: {
    'Title': insight.title.substring(0, 100),
    'Source Type': insight.sourceType,
    'Source': insight.source,
    'Summary': insight.summary,
    'Key Themes': insight.keyThemes,
    'Content Opportunities': insight.contentOpportunities,
    'Relevance Score': insight.relevanceScore,
    'Week': insight.week,
    'Created At': insight.createdAt
  }
}));

const data = $('Parse Analysis').first().json;
const hashUpdates = data.hashUpdates || [];

if (hashUpdates.length === 0) {
  return { json: { message: 'No hash updates needed' } };
}

// Return hash updates as items for System State upsert
return hashUpdates.map(h => ({
  json: {
    'Key': h.key,
    'Value': JSON.stringify({ hash: h.hash, checked_at: new Date().toISOString() }),
    'Updated At': new Date().toISOString().split('T')[0],
    'Updated By': 'WF-01 Intelligence'
  }
}));

const data = $('Parse Analysis').first().json;
const now = new Date().toLocaleString('en-ZA', { timeZone: 'Africa/Johannesburg' });
const analysis = data.analysis || {};

const trendsHtml = (analysis.trends || []).map(t =>
  `<li><strong>${t.topic}</strong> (relevance: ${t.relevance}/10) — ${t.source || 'mixed'}</li>`
).join('\n');

const movesHtml = (analysis.competitor_moves || []).map(m =>
  `<li><strong>${m.competitor}:</strong> ${m.move}<br>Our angle: ${m.our_angle}</li>`
).join('\n');

const oppsHtml = (analysis.opportunities || []).map(o =>
  `<li><strong>[${o.priority}]</strong> ${o.topic} — ${o.angle}<br>Platforms: ${(o.platforms || []).join(', ')}</li>`
).join('\n');

const estimatedCost = ((data.tokensUsed || 0) / 1000000 * 3).toFixed(4);

return {
  json: {
    subject: `Weekly Intelligence: ${(analysis.trends || []).length} trends, ${(analysis.opportunities || []).length} opportunities`,
    body: [
      '<h2>Weekly Intelligence Report</h2>',
      `<p><strong>Date:</strong> ${now}</p>`,
      `<p><strong>Sources analyzed:</strong> ${data.totalSources || 0}</p>`,
      '<hr>',
      `<p><em>${analysis.summary || 'No summary available'}</em></p>`,
      '<h3>Trends</h3>',
      `<ul>${trendsHtml || '<li>None identified</li>'}</ul>`,
      '<h3>Competitor Moves</h3>',
      `<ul>${movesHtml || '<li>None detected</li>'}</ul>`,
      '<h3>Content Opportunities</h3>',
      `<ul>${oppsHtml || '<li>None identified</li>'}</ul>`,
      '<hr>',
      `<p><strong>Tokens Used:</strong> ${(data.tokensUsed || 0).toLocaleString()}</p>`,
      `<p><strong>Estimated Cost:</strong> $${estimatedCost}</p>`,
      '<p>Insights stored in Research Insights table. WF-02 Strategy will use these on Monday 8:30 AM.</p>',
    ].join('\n')
  }
};
